#!/usr/bin/env node
// GENERATED by TestForge v3.0 — Payload Validator
// Run: node validate-payloads.mjs
// Validates all generated test payloads against Zod schemas without making HTTP requests.
// Use this as a fast local sanity check before running the full test suite.

import { readdir, readFile } from "fs/promises";
import { join, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));

// ANSI colors
const GREEN = "\x1b[32m";
const RED = "\x1b[31m";
const YELLOW = "\x1b[33m";
const RESET = "\x1b[0m";
const BOLD = "\x1b[1m";

let passed = 0;
let failed = 0;
const errors = [];

async function findTestFiles(dir) {
  const entries = await readdir(dir, { withFileTypes: true }).catch(() => []);
  const files = [];
  for (const entry of entries) {
    const fullPath = join(dir, entry.name);
    if (entry.isDirectory()) {
      files.push(...await findTestFiles(fullPath));
    } else if (entry.name.endsWith(".ts") && !entry.name.includes("config")) {
      files.push(fullPath);
    }
  }
  return files;
}

function extractPayloadFunctions(source) {
  // Extract basePayload_* function bodies
  const regex = /function basePayload_([\w]+)\(\)\s*\{[\s\S]*?return\s*(\{[\s\S]*?\});\s*\}/g;
  const payloads = [];
  let match;
  while ((match = regex.exec(source)) !== null) {
    const fnName = match[1];
    const bodyStr = match[2];
    payloads.push({ fnName, bodyStr });
  }
  return payloads;
}

function validatePayloadStructure(fnName, bodyStr) {
  // Basic structural validation without executing the code:
  // 1. Check all fields have values (no undefined)
  // 2. Check no TODO_ placeholders remain
  // 3. Check balanced braces
  const issues = [];

  if (bodyStr.includes("TODO_REPLACE")) {
    issues.push("Contains unresolved TODO_REPLACE placeholder");
  }
  if (bodyStr.includes("undefined")) {
    issues.push("Contains undefined value");
  }

  // Check balanced braces
  let depth = 0;
  for (const ch of bodyStr) {
    if (ch === "{") depth++;
    if (ch === "}") depth--;
    if (depth < 0) { issues.push("Unbalanced braces"); break; }
  }
  if (depth !== 0) issues.push("Unclosed brace in payload");

  // Check that there are actual fields (not just empty object)
  const fieldCount = (bodyStr.match(/:\s*[^,\n]+/g) || []).length;
  if (fieldCount === 0) {
    issues.push("Empty payload — no fields detected");
  }

  return issues;
}

async function main() {
  console.log(`\n${BOLD}TestForge Payload Validator v3.0${RESET}`);
  console.log("Scanning test files for payload functions...\n");

  const testDir = join(__dirname, "tests");
  const testFiles = await findTestFiles(testDir);

  if (testFiles.length === 0) {
    console.log(`${YELLOW}No test files found in ./tests/${RESET}`);
    console.log("Run TestForge to generate test files first.");
    process.exit(0);
  }

  console.log(`Found ${testFiles.length} test files\n`);

  for (const filePath of testFiles) {
    const source = await readFile(filePath, "utf-8");
    const payloads = extractPayloadFunctions(source);
    const relPath = filePath.replace(__dirname + "/", "");

    if (payloads.length === 0) continue;

    for (const { fnName, bodyStr } of payloads) {
      const issues = validatePayloadStructure(fnName, bodyStr);
      if (issues.length === 0) {
        console.log(`  ${GREEN}✓${RESET} ${relPath} → basePayload_${fnName}`);
        passed++;
      } else {
        console.log(`  ${RED}✗${RESET} ${relPath} → basePayload_${fnName}`);
        for (const issue of issues) {
          console.log(`    ${RED}→ ${issue}${RESET}`);
        }
        errors.push({ file: relPath, fn: fnName, issues });
        failed++;
      }
    }
  }

  console.log(`\n${BOLD}Results:${RESET}`);
  console.log(`  ${GREEN}${passed} payloads valid${RESET}`);
  if (failed > 0) {
    console.log(`  ${RED}${failed} payloads invalid${RESET}`);
    console.log("\nFix the issues above before running the full test suite.");
    process.exit(1);
  } else {
    console.log(`\n${GREEN}${BOLD}All payloads are valid — ready to run tests!${RESET}`);
    console.log("Run: npm test");
    process.exit(0);
  }
}

main().catch(err => {
  console.error("Validator error:", err);
  process.exit(1);
});
